package com.example.mpos.inventory;
import android.database.Cursor;import android.os.Bundle;import android.widget.*;import androidx.appcompat.app.AppCompatActivity;import com.example.mpos.R;import com.example.mpos.auth.PermissionHelper;import com.example.mpos.database.DatabaseHelper;import java.util.*;
public class InventoryHistoryActivity extends AppCompatActivity{public void onCreate(Bundle b){super.onCreate(b);if(!PermissionHelper.requireAdmin(this))return;setContentView(R.layout.activity_inventory_history);Cursor c=new DatabaseHelper(this).getReadableDatabase().rawQuery("SELECT p.name,t.transaction_type,t.quantity_change,t.quantity_after,t.note FROM inventory_transactions t JOIN products p ON p.id=t.product_id ORDER BY t.created_at DESC LIMIT 100",null);List<String>rows=new ArrayList<>();try{while(c.moveToNext())rows.add(c.getString(0)+"\n"+c.getString(1)+" • "+c.getInt(2)+" • Tồn sau: "+c.getInt(3)+(c.getString(4)==null?"":"\n"+c.getString(4)));}finally{c.close();}if(rows.isEmpty())rows.add("Chưa có lịch sử biến động kho");((ListView)findViewById(R.id.listInventoryHistory)).setAdapter(new ArrayAdapter<>(this,android.R.layout.simple_list_item_1,rows));findViewById(R.id.btnBack).setOnClickListener(v->finish());}}
